class Solution {
    private int[] w;
    private int sum;
    private Random random;

    public Solution(int[] w) {
        this.w = w;
        this.sum = 0;
        this.random = new Random();
        for (int weight : w) {
            sum += weight;
        }
    }

    public int pickIndex() {
        int target = random.nextInt(sum);
        int cumulativeSum = 0;
        for (int i = 0; i < w.length; i++) {
            cumulativeSum += w[i];
            if (target < cumulativeSum) {
                return i;
            }
        }
        return w.length - 1;
    }
}

